local function DYCSetEightFaced(inst) if inst.Transform.SetEightFaced then inst.Transform:SetEightFaced() end end local function DYCMakePlacer(name, bank, build, anim, onground, snap, metersnap, scale, snap_to_flood, fixedcameraoffset, facing, hide_on_invalid, postinit_fn) local function fn(Sim) local inst = CreateEntity() inst.entity:AddTransform() inst.entity:AddAnimState() inst.AnimState:SetBank(bank) inst.AnimState:SetBuild(build) inst.AnimState:PlayAnimation(anim, true) inst.AnimState:SetLightOverride(0x1) if facing == "two" then inst.Transform:SetTwoFaced() elseif facing == "four" then inst.Transform:SetFourFaced() elseif facing == "six" then inst.Transform:SetSixFaced() elseif facing == "eight" then DYCSetEightFaced(inst) end inst:AddComponent( "placer" ) inst.persists = false inst.components.placer.snaptogrid = snap inst.components.placer.snap_to_meters = metersnap inst.components.placer.snap_to_flood = snap_to_flood inst.components.placer.fixedcameraoffset = fixedcameraoffset inst.components.placer.hide_on_invalid = hide_on_invalid inst.components.placer.linked = {} function inst.components.placer:LinkEntity(ent) table.insert(self.linked, ent) end local oldonupdate = inst.components.placer.OnUpdate inst.components.placer.OnUpdate = function(self, dt) oldonupdate(self, dt) if self.fixedcameraoffset ~= nil then local rot = self.fixedcameraoffset - TheCamera:GetHeading() self.inst.Transform:SetRotation(rot) for i, v in ipairs(self.linked) do v.Transform:SetRotation(rot) end end if self.onupdatetransform ~= nil then self.onupdatetransform(self.inst) end end scale = scale or 0x1 inst.Transform:SetScale(scale, scale, scale) if onground then inst.AnimState:SetOrientation(ANIM_ORIENTATION.OnGround) end if postinit_fn ~= nil then postinit_fn(inst) end return inst end return Prefab(name, fn) end return DYCMakePlacer 